import{_ as s,o as i,c as a,ag as o}from"./chunks/framework.CTpQozEL.js";const u=JSON.parse('{"title":"Discord","description":"Discord 봇 지원 상태, 기능 및 구성","frontmatter":{"title":"Discord","description":"Discord 봇 지원 상태, 기능 및 구성"},"headers":[],"relativePath":"channels/discord.md","filePath":"channels/discord.md","lastUpdated":null}'),n={name:"channels/discord.md"};function l(t,e,d,c,r,p){return i(),a("div",null,[...e[0]||(e[0]=[o('<p>공식 Discord gateway를 통해 DM 및 guild 채널에서 사용할 준비가 되어 있습니다.</p><blockquote><p><strong>페어링</strong> Discord DM은 기본적으로 페어링 모드입니다.</p></blockquote><blockquote><p><strong>슬래시 명령</strong> 네이티브 명령 동작 및 명령 카탈로그.</p></blockquote><blockquote><p><strong>채널 문제 해결</strong> 채널 간 진단 및 수리 흐름.</p></blockquote><h2 id="빠른-설정" tabindex="-1">빠른 설정 <a class="header-anchor" href="#빠른-설정" aria-label="Permalink to &quot;빠른 설정&quot;">​</a></h2><p>봇이 포함된 새 애플리케이션을 생성하고, 봇을 서버에 추가한 다음, OpenClaw에 페어링해야 합니다. 봇은 본인의 프라이빗 서버에 추가하는 것을 권장합니다. 아직 프라이빗 서버가 없다면 <a href="https://support.discord.com/hc/en-us/articles/204849977-How-do-I-create-a-server" target="_blank" rel="noreferrer">먼저 생성</a>하십시오 (<strong>Create My Own &gt; For me and my friends</strong> 선택).</p><ol><li><p><strong>Discord 애플리케이션 및 봇 생성</strong></p><p><a href="https://discord.com/developers/applications" target="_blank" rel="noreferrer">Discord Developer Portal</a>로 이동하여 <strong>New Application</strong>을 클릭합니다. &quot;OpenClaw&quot;와 같은 이름을 지정합니다.</p><pre><code>사이드바의 **Bot**을 클릭합니다. **Username**을 OpenClaw 에이전트 이름으로 설정합니다.\n</code></pre></li><li><p><strong>권한 있는 intent 활성화</strong></p></li></ol><p><strong>Bot</strong> 페이지에서 아래로 스크롤하여 <strong>Privileged Gateway Intents</strong>로 이동한 뒤 다음을 활성화합니다:</p><pre><code>   - **Message Content Intent** (필수)\n   - **Server Members Intent** (권장; 역할 허용 목록 및 이름-ID 매칭에 필요)\n   - **Presence Intent** (선택 사항; presence 업데이트에만 필요)\n</code></pre><ol start="3"><li><strong>봇 토큰 복사</strong></li></ol><p><strong>Bot</strong> 페이지 상단으로 다시 스크롤하고 <strong>Reset Token</strong>을 클릭합니다.</p><pre><code>   ::: info NOTE\n</code></pre><p>이름과 달리, 이는 첫 번째 토큰을 생성하는 것입니다 — &quot;리셋&quot;되는 것은 없습니다. :::</p><pre><code>   토큰을 복사하여 어딘가에 저장하십시오. 이는 **Bot Token**이며 곧 필요합니다.\n</code></pre><ol start="4"><li><strong>초대 URL 생성 및 봇을 서버에 추가</strong></li></ol><p>사이드바의 <strong>OAuth2</strong>를 클릭합니다. 봇을 서버에 추가할 적절한 권한이 포함된 초대 URL을 생성합니다.</p><pre><code>   **OAuth2 URL Generator**로 스크롤하여 다음을 활성화합니다:\n\n   - `bot`\n   - `applications.commands`\n\n   아래에 **Bot Permissions** 섹션이 나타납니다. 최소한 다음을 활성화합니다:\n\n   **General Permissions**\n     - View Channels\n   **Text Permissions**\n     - Send Messages\n     - Read Message History\n     - Embed Links\n     - Attach Files\n     - Add Reactions (선택 사항)\n\n   이는 일반 텍스트 채널의 기준 세트입니다. 스레드를 생성하거나 이어가는 forum 또는 media 채널 워크플로를 포함하여 Discord 스레드에 게시할 계획이라면, **Send Messages in Threads**도 활성화하십시오.\n   맨 아래에서 생성된 URL을 복사하고 브라우저에 붙여넣어 서버를 선택한 뒤 **Continue**를 클릭하여 연결합니다. 이제 Discord 서버에서 봇이 보여야 합니다.\n</code></pre><ol start="5"><li><strong>Developer Mode 활성화 및 ID 수집</strong></li></ol><p>다시 Discord 앱으로 돌아가서, 내부 ID를 복사할 수 있도록 Developer Mode를 활성화해야 합니다.</p><pre><code>   1. **User Settings** (아바타 옆 톱니바퀴 아이콘) 클릭 → **Advanced** → **Developer Mode** 토글 켜기\n   2. 사이드바에서 **서버 아이콘** 우클릭 → **Copy Server ID**\n   3. **내 아바타** 우클릭 → **Copy User ID**\n\n   **Server ID**와 **User ID**를 Bot Token과 함께 저장하십시오 — 다음 단계에서 세 가지 모두 OpenClaw에 전달합니다.\n</code></pre><ol start="6"><li><strong>서버 멤버의 DM 허용</strong></li></ol><p>페어링이 작동하려면 Discord가 봇이 사용자에게 DM을 보낼 수 있도록 허용해야 합니다. <strong>서버 아이콘</strong> 우클릭 → <strong>Privacy Settings</strong> → <strong>Direct Messages</strong> 토글 켜기.</p><pre><code>   이를 통해 서버 멤버(봇 포함)가 DM을 보낼 수 있습니다. OpenClaw와 Discord DM을 사용하려면 이 설정을 유지하십시오. guild 채널만 사용할 계획이라면 페어링 후 DM을 비활성화할 수 있습니다.\n</code></pre><ol start="7"><li><strong>봇 토큰을 안전하게 설정 (채팅에서 전송하지 말 것)</strong></li></ol><p>Discord 봇 토큰은 비밀(비밀번호와 같음)입니다. 에이전트에 메시지를 보내기 전에 OpenClaw를 실행하는 머신에 설정하십시오.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> DISCORD_BOT_TOKEN</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;YOUR_BOT_TOKEN&quot;</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> channels.discord.token</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --ref-provider</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> default</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --ref-source</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> env</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --ref-id</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> DISCORD_BOT_TOKEN</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dry-run</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> channels.discord.token</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --ref-provider</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> default</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --ref-source</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> env</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --ref-id</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> DISCORD_BOT_TOKEN</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> channels.discord.enabled</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --strict-json</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span></span></code></pre></div><pre><code>   OpenClaw가 이미 백그라운드 서비스로 실행 중이라면, OpenClaw Mac 앱을 통해 또는 `openclaw gateway run` 프로세스를 중지하고 재시작하여 재시작하십시오.\n</code></pre><ol start="8"><li><strong>OpenClaw 구성 및 페어링</strong></li></ol><p><strong>에이전트에게 요청</strong></p><p>기존 채널(예: Telegram)에서 OpenClaw 에이전트와 대화하여 알려주십시오. Discord가 첫 번째 채널이라면 CLI / config 탭을 사용하십시오.</p><pre><code>       &gt; &quot;설정에 Discord 봇 토큰을 이미 설정했습니다. User ID `&lt;user_id&gt;`와 Server ID `&lt;server_id&gt;`로 Discord 설정을 마무리해 주세요.&quot;\n\n\n     **CLI / config**\n</code></pre><p>파일 기반 구성을 선호하는 경우 다음을 설정하십시오:</p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  channels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    discord</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      enabled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      token</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        source</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;env&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        provider</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;default&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        id</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;DISCORD_BOT_TOKEN&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><pre><code>       기본 계정의 환경 변수 폴백:\n</code></pre><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">DISCORD_BOT_TOKEN</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">...</span></span></code></pre></div><pre><code>       일반 텍스트 `token` 값이 지원됩니다. `channels.discord.token`에 대해 env/file/exec provider 전반에서 SecretRef 값도 지원됩니다. [비밀 관리](/gateway/secrets)를 참조하십시오.\n</code></pre><ol start="9"><li><strong>첫 DM 페어링 승인</strong></li></ol><p>gateway가 실행될 때까지 기다린 다음 Discord에서 봇에게 DM을 보내십시오. 봇은 페어링 코드로 응답합니다.</p><pre><code>   **에이전트에게 요청**\n</code></pre><p>기존 채널에서 에이전트에게 페어링 코드를 전송하십시오:</p><pre><code>       &gt; &quot;이 Discord 페어링 코드를 승인해 주세요: `&lt;CODE&gt;`&quot;\n\n\n     **CLI**\n</code></pre><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">   openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> discord</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">   openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> approve</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> discord</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">COD</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">E</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><pre><code>   페어링 코드는 1시간 후 만료됩니다.\n\n   이제 DM을 통해 Discord에서 에이전트와 대화할 수 있어야 합니다.\n</code></pre><div class="info custom-block"><p class="custom-block-title">NOTE</p><p>토큰 확인은 계정을 고려합니다. 구성 토큰 값이 환경 변수 폴백보다 우선합니다. <code>DISCORD_BOT_TOKEN</code>은 기본 계정에만 사용됩니다. 고급 아웃바운드 호출(message tool/채널 액션)의 경우, 해당 호출에는 명시적 호출별 <code>token</code>이 사용됩니다. 이는 send 및 read/probe 스타일 액션(예: read/search/fetch/thread/pins/permissions)에 적용됩니다. 계정 정책/재시도 설정은 여전히 활성 런타임 스냅샷에서 선택된 계정에서 가져옵니다.</p></div><h2 id="권장-guild-워크스페이스-설정" tabindex="-1">권장: guild 워크스페이스 설정 <a class="header-anchor" href="#권장-guild-워크스페이스-설정" aria-label="Permalink to &quot;권장: guild 워크스페이스 설정&quot;">​</a></h2><p>DM이 작동하면, Discord 서버를 각 채널이 자체 컨텍스트를 가진 에이전트 세션을 얻는 완전한 워크스페이스로 설정할 수 있습니다. 본인과 봇만 있는 프라이빗 서버에 권장됩니다.</p><ol><li><p><strong>서버를 guild 허용 목록에 추가</strong></p><p>이를 통해 에이전트가 DM뿐만 아니라 서버의 모든 채널에서 응답할 수 있습니다.</p><pre><code>**에이전트에게 요청**\n</code></pre></li></ol><blockquote><p>&quot;내 Discord Server ID <code>&lt;server_id&gt;</code>를 guild 허용 목록에 추가해 주세요&quot;</p></blockquote><pre><code>     **Config**\n</code></pre><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">   {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">     channels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">       discord</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">         groupPolicy</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;allowlist&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">         guilds</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">           YOUR_SERVER_ID</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">             requireMention</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">             users</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;YOUR_USER_ID&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">           },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">         },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">       },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">     },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">   }</span></span></code></pre></div><ol start="2"><li><strong>@mention 없이 응답 허용</strong></li></ol><p>기본적으로 에이전트는 @mention된 경우에만 guild 채널에서 응답합니다. 프라이빗 서버에서는 모든 메시지에 응답하도록 하고 싶을 것입니다.</p><pre><code>   **에이전트에게 요청**\n</code></pre><blockquote><p>&quot;이 서버에서 @mention 없이도 에이전트가 응답하도록 허용해 주세요&quot;</p></blockquote><pre><code>     **Config**\n</code></pre><p>guild 구성에서 <code>requireMention: false</code>를 설정하십시오:</p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  channels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    discord</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      guilds</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        YOUR_SERVER_ID</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">          requireMention</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><ol start="3"><li><strong>guild 채널의 메모리 계획</strong></li></ol><p>기본적으로 장기 메모리(MEMORY.md)는 DM 세션에서만 로드됩니다. guild 채널은 MEMORY.md를 자동 로드하지 않습니다.</p><pre><code>   **에이전트에게 요청**\n</code></pre><blockquote><p>&quot;Discord 채널에서 질문할 때, MEMORY.md의 장기 컨텍스트가 필요하면 memory_search 또는 memory_get을 사용해 주세요.&quot;</p></blockquote><pre><code>     **수동**\n</code></pre><p>모든 채널에서 공유 컨텍스트가 필요하다면, 안정적인 지침을 <code>AGENTS.md</code> 또는 <code>USER.md</code>에 넣으십시오 (모든 세션에 주입됨). 장기 노트는 <code>MEMORY.md</code>에 유지하고 메모리 도구로 필요 시 접근하십시오.</p><p>이제 Discord 서버에서 채널 몇 개를 만들고 대화를 시작하십시오. 에이전트는 채널 이름을 볼 수 있으며, 각 채널은 자체 격리된 세션을 갖습니다 — 따라서 <code>#coding</code>, <code>#home</code>, <code>#research</code> 등 워크플로에 맞는 채널을 설정할 수 있습니다.</p><h2 id="런타임-모델" tabindex="-1">런타임 모델 <a class="header-anchor" href="#런타임-모델" aria-label="Permalink to &quot;런타임 모델&quot;">​</a></h2><ul><li>Gateway가 Discord 연결을 소유합니다.</li><li>응답 라우팅은 결정적입니다: Discord 인바운드는 Discord로 다시 응답합니다.</li><li>기본적으로 (<code>session.dmScope=main</code>), 다이렉트 채팅은 에이전트 메인 세션(<code>agent:main:main</code>)을 공유합니다.</li><li>Guild 채널은 격리된 세션 키(<code>agent:&amp;lt;agentId&amp;gt;:discord:channel:&amp;lt;channelId&amp;gt;</code>)입니다.</li><li>그룹 DM은 기본적으로 무시됩니다 (<code>channels.discord.dm.groupEnabled=false</code>).</li><li>네이티브 슬래시 명령은 격리된 명령 세션(<code>agent:&amp;lt;agentId&amp;gt;:discord:slash:&amp;lt;userId&amp;gt;</code>)에서 실행되며, 동시에 <code>CommandTargetSessionKey</code>를 라우팅된 대화 세션으로 전달합니다.</li></ul><h2 id="forum-채널" tabindex="-1">Forum 채널 <a class="header-anchor" href="#forum-채널" aria-label="Permalink to &quot;Forum 채널&quot;">​</a></h2><p>Discord forum 및 media 채널은 스레드 게시만 허용합니다. OpenClaw는 이를 생성하는 두 가지 방법을 지원합니다:</p><ul><li>Forum 부모(<code>channel:&amp;lt;forumId&amp;gt;</code>)에 메시지를 보내 스레드를 자동 생성합니다. 스레드 제목은 메시지의 첫 번째 비어 있지 않은 줄을 사용합니다.</li><li>스레드를 직접 생성하려면 <code>openclaw message thread create</code>를 사용하십시오. Forum 채널에는 <code>--message-id</code>를 전달하지 마십시오.</li></ul><p>예시: forum 부모에 보내 스레드 생성 �OC_CODE_1�</p><p>예시: forum 스레드를 명시적으로 생성 �OC_CODE_2�</p><p>Forum 부모는 Discord component를 허용하지 않습니다. Component가 필요하다면 스레드 자체(<code>channel:&amp;lt;threadId&amp;gt;</code>)로 전송하십시오.</p><h2 id="인터랙티브-component" tabindex="-1">인터랙티브 component <a class="header-anchor" href="#인터랙티브-component" aria-label="Permalink to &quot;인터랙티브 component&quot;">​</a></h2><p>OpenClaw는 에이전트 메시지에 대해 Discord components v2 컨테이너를 지원합니다. <code>components</code> 페이로드가 포함된 message tool을 사용하십시오. 인터랙션 결과는 일반 인바운드 메시지로 에이전트에 다시 라우팅되고 기존 Discord <code>replyToMode</code> 설정을 따릅니다.</p><p>지원되는 블록:</p><ul><li><code>text</code>, <code>section</code>, <code>separator</code>, <code>actions</code>, <code>media-gallery</code>, <code>file</code></li><li>Action row는 최대 5개의 버튼 또는 단일 select 메뉴를 허용합니다</li><li>Select 타입: <code>string</code>, <code>user</code>, <code>role</code>, <code>mentionable</code>, <code>channel</code></li></ul><p>기본적으로 component는 단일 사용입니다. <code>components.reusable=true</code>로 설정하여 버튼, select, 폼이 만료될 때까지 여러 번 사용되도록 허용하십시오.</p><p>버튼 클릭을 누가 할 수 있는지 제한하려면 해당 버튼에 <code>allowedUsers</code>(Discord user ID, 태그 또는 <code>*</code>)를 설정하십시오. 구성된 경우 일치하지 않는 사용자는 ephemeral 거부를 받습니다.</p><p><code>/model</code> 및 <code>/models</code> 슬래시 명령은 provider와 model 드롭다운에 Submit 단계가 추가된 인터랙티브 모델 선택기를 엽니다. <code>commands.modelsWrite=false</code>가 아닌 경우, <code>/models add</code>는 채팅에서 새 provider/model 항목 추가도 지원하며, 새로 추가된 모델은 gateway를 재시작하지 않고도 나타납니다. 선택기 응답은 ephemeral이며 호출한 사용자만 사용할 수 있습니다.</p><p>파일 첨부:</p><ul><li><code>file</code> 블록은 attachment 참조(<code>attachment://&amp;lt;filename&amp;gt;</code>)를 가리켜야 합니다</li><li><code>media</code>/<code>path</code>/<code>filePath</code>(단일 파일)를 통해 attachment를 제공하십시오. 여러 파일은 <code>media-gallery</code>를 사용하십시오</li><li>attachment 참조와 일치해야 하는 경우 업로드 이름을 재정의하려면 <code>filename</code>을 사용하십시오</li></ul><p>Modal 폼:</p><ul><li><code>components.modal</code>에 최대 5개의 필드 추가</li><li>필드 타입: <code>text</code>, <code>checkbox</code>, <code>radio</code>, <code>select</code>, <code>role-select</code>, <code>user-select</code></li><li>OpenClaw는 트리거 버튼을 자동으로 추가합니다</li></ul><p>예시: �OC_CODE_3�</p><h2 id="접근-제어-및-라우팅" tabindex="-1">접근 제어 및 라우팅 <a class="header-anchor" href="#접근-제어-및-라우팅" aria-label="Permalink to &quot;접근 제어 및 라우팅&quot;">​</a></h2><p><strong>DM 정책</strong></p><p><code>channels.discord.dmPolicy</code>는 DM 접근을 제어합니다 (레거시: <code>channels.discord.dm.policy</code>):</p><pre><code>- `pairing` (기본값)\n- `allowlist`\n- `open` (`channels.discord.allowFrom`이 `&quot;*&quot;`를 포함해야 함; 레거시: `channels.discord.dm.allowFrom`)\n- `disabled`\n\nDM 정책이 open이 아닌 경우, 알 수 없는 사용자는 차단됩니다 (또는 `pairing` 모드에서 페어링이 요청됩니다).\n\n다중 계정 우선순위:\n\n- `channels.discord.accounts.default.allowFrom`은 `default` 계정에만 적용됩니다.\n- 명명된 계정은 자체 `allowFrom`이 설정되지 않은 경우 `channels.discord.allowFrom`을 상속합니다.\n- 명명된 계정은 `channels.discord.accounts.default.allowFrom`을 상속하지 않습니다.\n\n전달을 위한 DM 타겟 형식:\n\n- `user:&amp;lt;id&amp;gt;`\n- `&lt;@id&gt;` 멘션\n\n단순 숫자 ID는 모호하여 명시적 user/channel 타겟 종류가 제공되지 않는 한 거부됩니다.\n</code></pre><p><strong>Guild 정책</strong></p><p>Guild 처리는 <code>channels.discord.groupPolicy</code>로 제어됩니다:</p><pre><code>- `open`\n- `allowlist`\n- `disabled`\n\n`channels.discord`가 존재할 때의 보안 기준선은 `allowlist`입니다.\n\n`allowlist` 동작:\n\n- guild는 `channels.discord.guilds`와 일치해야 합니다 (`id` 선호, slug 허용)\n- 선택적 발신자 허용 목록: `users` (안정적인 ID 권장)과 `roles` (role ID만); 어느 쪽이든 구성되면 발신자는 `users` OR `roles`와 일치할 때 허용됩니다\n- 직접 이름/태그 매칭은 기본적으로 비활성화됩니다. `channels.discord.dangerouslyAllowNameMatching: true`는 비상 호환성 모드로만 활성화하십시오\n- 이름/태그는 `users`에 지원되지만, ID가 더 안전합니다. `openclaw security audit`은 이름/태그 항목이 사용될 때 경고합니다\n- guild에 `channels`가 구성되어 있으면, 목록에 없는 채널은 거부됩니다\n- guild에 `channels` 블록이 없으면, 허용 목록에 있는 해당 guild의 모든 채널이 허용됩니다\n\n예시:\n</code></pre><p>�OC_CODE_4�</p><pre><code>`DISCORD_BOT_TOKEN`만 설정하고 `channels.discord` 블록을 만들지 않으면, `channels.defaults.groupPolicy`가 `open`이더라도 런타임 폴백은 `groupPolicy=&quot;allowlist&quot;`입니다 (로그에 경고와 함께).\n</code></pre><p><strong>멘션 및 그룹 DM</strong></p><p>Guild 메시지는 기본적으로 멘션 게이팅됩니다.</p><pre><code>멘션 감지에는 다음이 포함됩니다:\n\n- 명시적 봇 멘션\n- 구성된 멘션 패턴 (`agents.list[].groupChat.mentionPatterns`, 폴백 `messages.groupChat.mentionPatterns`)\n- 지원되는 경우 암시적 봇 응답 동작\n\n`requireMention`은 guild/channel별로 구성됩니다 (`channels.discord.guilds...`).\n`ignoreOtherMentions`는 봇이 아닌 다른 사용자/역할을 멘션하는 메시지를 선택적으로 삭제합니다 (@everyone/@here 제외).\n\n그룹 DM:\n\n- 기본값: 무시됨 (`dm.groupEnabled=false`)\n- `dm.groupChannels`를 통한 선택적 허용 목록 (채널 ID 또는 slug)\n</code></pre><h3 id="역할-기반-에이전트-라우팅" tabindex="-1">역할 기반 에이전트 라우팅 <a class="header-anchor" href="#역할-기반-에이전트-라우팅" aria-label="Permalink to &quot;역할 기반 에이전트 라우팅&quot;">​</a></h3><p><code>bindings[].match.roles</code>를 사용하여 Discord guild 멤버를 role ID로 다른 에이전트에 라우팅합니다. 역할 기반 바인딩은 role ID만 허용하며 peer 또는 parent-peer 바인딩 이후, guild 전용 바인딩 이전에 평가됩니다. 바인딩이 다른 match 필드도 설정하는 경우(예: <code>peer</code> + <code>guildId</code> + <code>roles</code>), 구성된 모든 필드가 일치해야 합니다. �OC_CODE_5�</p><h2 id="네이티브-명령-및-명령-인증" tabindex="-1">네이티브 명령 및 명령 인증 <a class="header-anchor" href="#네이티브-명령-및-명령-인증" aria-label="Permalink to &quot;네이티브 명령 및 명령 인증&quot;">​</a></h2><ul><li><code>commands.native</code>는 기본적으로 <code>&quot;auto&quot;</code>이며 Discord에서 활성화됩니다.</li><li>채널별 재정의: <code>channels.discord.commands.native</code>.</li><li><code>commands.native=false</code>는 이전에 등록된 Discord 네이티브 명령을 명시적으로 지웁니다.</li><li>네이티브 명령 인증은 일반 메시지 처리와 동일한 Discord 허용 목록/정책을 사용합니다.</li><li>명령은 인증되지 않은 사용자에게도 Discord UI에 보일 수 있지만, 실행 시 OpenClaw 인증이 여전히 시행되며 &quot;not authorized&quot;를 반환합니다.</li></ul><p>명령 카탈로그 및 동작은 <a href="/openclaw-docs-ko/tools/slash-commands">슬래시 명령</a>을 참조하십시오.</p><p>기본 슬래시 명령 설정:</p><ul><li><code>ephemeral: true</code></li></ul><h2 id="기능-상세" tabindex="-1">기능 상세 <a class="header-anchor" href="#기능-상세" aria-label="Permalink to &quot;기능 상세&quot;">​</a></h2><details class="details custom-block"><summary>응답 태그 및 네이티브 응답</summary><p>Discord는 에이전트 출력에서 응답 태그를 지원합니다:</p><pre><code>- `[[reply_to_current]]`\n- `[[reply_to:&amp;lt;id&amp;gt;]]`\n\n`channels.discord.replyToMode`로 제어됩니다:\n\n- `off` (기본값)\n- `first`\n- `all`\n- `batched`\n\n참고: `off`는 암시적 응답 스레딩을 비활성화합니다. 명시적 `[[reply_to_*]]` 태그는 여전히 처리됩니다.\n`first`는 항상 턴의 첫 번째 아웃바운드 Discord 메시지에 암시적 네이티브 응답 참조를 첨부합니다.\n`batched`는 인바운드 턴이 여러 메시지의 디바운스된 배치인 경우에만 Discord의 암시적 네이티브 응답 참조를 첨부합니다. 이는 매 단일 메시지 턴이 아니라 모호한 버스티 채팅에 주로 네이티브 응답을 원할 때 유용합니다.\n\n메시지 ID는 context/history에 표시되어 에이전트가 특정 메시지를 대상으로 지정할 수 있습니다.\n</code></pre></details><details class="details custom-block"><summary>라이브 스트림 미리보기</summary><p>OpenClaw는 임시 메시지를 보낸 뒤 텍스트가 도착하면 편집하여 초안 응답을 스트리밍할 수 있습니다. <code>channels.discord.streaming</code>은 <code>off</code> (기본값) | <code>partial</code> | <code>block</code> | <code>progress</code>를 받습니다. <code>progress</code>는 Discord에서 <code>partial</code>로 매핑됩니다. <code>streamMode</code>는 레거시 별칭이며 자동으로 마이그레이션됩니다.</p><pre><code>기본값은 `off`로 유지되는데, 여러 봇이나 gateway가 계정을 공유할 때 Discord 미리보기 편집이 속도 제한에 빠르게 도달하기 때문입니다.\n</code></pre><p>�OC_CODE_6�</p><pre><code>- `partial`은 토큰이 도착할 때 단일 미리보기 메시지를 편집합니다.\n- `block`은 초안 크기 청크를 방출합니다 (`draftChunk`를 사용하여 크기 및 중단점 조정, `textChunkLimit`으로 제한됨).\n- 미디어, 오류, 명시적 응답 최종본은 대기 중인 미리보기 편집을 취소합니다.\n- `streaming.preview.toolProgress` (기본값 `true`)는 tool/progress 업데이트가 미리보기 메시지를 재사용할지 제어합니다.\n\n미리보기 스트리밍은 텍스트 전용입니다. 미디어 응답은 일반 전달로 폴백됩니다. `block` 스트리밍이 명시적으로 활성화된 경우, OpenClaw는 이중 스트리밍을 방지하기 위해 미리보기 스트림을 건너뜁니다.\n</code></pre></details><details class="details custom-block"><summary>히스토리, 컨텍스트 및 스레드 동작</summary><p>Guild 히스토리 컨텍스트:</p><pre><code>- `channels.discord.historyLimit` 기본값 `20`\n- 폴백: `messages.groupChat.historyLimit`\n- `0`은 비활성화\n\nDM 히스토리 제어:\n\n- `channels.discord.dmHistoryLimit`\n- `channels.discord.dms[&quot;&amp;lt;user_id&amp;gt;&quot;].historyLimit`\n\n스레드 동작:\n\n- Discord 스레드는 채널 세션으로 라우팅되며 재정의되지 않는 한 부모 채널 구성을 상속합니다.\n- `channels.discord.thread.inheritParent` (기본값 `false`)는 새 자동 스레드가 부모 transcript에서 시딩하도록 옵트인합니다. 계정별 재정의는 `channels.discord.accounts.&amp;lt;id&amp;gt;.thread.inheritParent`에 있습니다.\n- Message-tool 반응은 `user:&amp;lt;id&amp;gt;` DM 타겟을 확인할 수 있습니다.\n- `guilds.&amp;lt;guild&amp;gt;.channels.&amp;lt;channel&amp;gt;.requireMention: false`는 응답 단계 활성화 폴백 중에 보존됩니다.\n\n채널 topic은 **신뢰할 수 없는** 컨텍스트로 주입됩니다. 허용 목록은 에이전트를 트리거할 수 있는 사람을 게이팅하며, 전체 보조 컨텍스트 편집 경계는 아닙니다.\n</code></pre></details><details class="details custom-block"><summary>서브에이전트를 위한 스레드 바인딩 세션</summary><p>Discord는 스레드를 세션 타겟에 바인딩하여 해당 스레드의 후속 메시지가 동일한 세션(서브에이전트 세션 포함)으로 계속 라우팅되도록 할 수 있습니다.</p><pre><code>명령:\n\n- `/focus &amp;lt;target&amp;gt;` 현재/새 스레드를 서브에이전트/세션 타겟에 바인딩\n- `/unfocus` 현재 스레드 바인딩 제거\n- `/agents` 활성 실행 및 바인딩 상태 표시\n- `/session idle &amp;lt;duration|off&amp;gt;` focused 바인딩의 비활성 자동 unfocus 검사/업데이트\n- `/session max-age &amp;lt;duration|off&amp;gt;` focused 바인딩의 하드 max age 검사/업데이트\n\nConfig:\n</code></pre><p>�OC_CODE_7�</p><pre><code>참고:\n\n- `session.threadBindings.*`는 전역 기본값을 설정합니다.\n- `channels.discord.threadBindings.*`는 Discord 동작을 재정의합니다.\n- `sessions_spawn({ thread: true })`를 위해 스레드를 자동 생성/바인딩하려면 `spawnSubagentSessions`가 true여야 합니다.\n- ACP(`/acp spawn ... --thread ...` 또는 `sessions_spawn({ runtime: &quot;acp&quot;, thread: true })`)를 위해 스레드를 자동 생성/바인딩하려면 `spawnAcpSessions`가 true여야 합니다.\n- 계정에 대해 스레드 바인딩이 비활성화된 경우, `/focus` 및 관련 스레드 바인딩 작업은 사용할 수 없습니다.\n\n[서브에이전트](/tools/subagents), [ACP 에이전트](/tools/acp-agents), [구성 참조](/gateway/configuration-reference)를 참조하십시오.\n</code></pre></details><details class="details custom-block"><summary>영구 ACP 채널 바인딩</summary><p>안정적인 &quot;항상 켜져 있는&quot; ACP 워크스페이스를 위해, Discord 대화를 타겟으로 하는 최상위 타입이 지정된 ACP 바인딩을 구성하십시오.</p><pre><code>Config 경로:\n\n- `type: &quot;acp&quot;` 및 `match.channel: &quot;discord&quot;`가 있는 `bindings[]`\n\n예시:\n</code></pre><p>�OC_CODE_8�</p><pre><code>참고:\n\n- `/acp spawn codex --bind here`는 현재 채널 또는 스레드를 제자리에서 바인딩하고 향후 메시지를 동일한 ACP 세션으로 유지합니다. 스레드 메시지는 부모 채널 바인딩을 상속합니다.\n- 바인딩된 채널 또는 스레드에서 `/new`와 `/reset`은 동일한 ACP 세션을 제자리에서 리셋합니다. 임시 스레드 바인딩은 활성화되어 있는 동안 타겟 확인을 재정의할 수 있습니다.\n- `spawnAcpSessions`는 OpenClaw가 `--thread auto|here`를 통해 자식 스레드를 생성/바인딩해야 할 때만 필요합니다.\n\n바인딩 동작 상세는 [ACP 에이전트](/tools/acp-agents)를 참조하십시오.\n</code></pre></details><details class="details custom-block"><summary>반응 알림</summary><p>Guild별 반응 알림 모드:</p><pre><code>- `off`\n- `own` (기본값)\n- `all`\n- `allowlist` (`guilds.&amp;lt;id&amp;gt;.users` 사용)\n\n반응 이벤트는 시스템 이벤트로 변환되어 라우팅된 Discord 세션에 첨부됩니다.\n</code></pre></details><details class="details custom-block"><summary>확인 반응</summary><p><code>ackReaction</code>은 OpenClaw가 인바운드 메시지를 처리하는 동안 확인 이모지를 전송합니다.</p><pre><code>확인 순서:\n\n- `channels.discord.accounts.&amp;lt;accountId&amp;gt;.ackReaction`\n- `channels.discord.ackReaction`\n- `messages.ackReaction`\n- 에이전트 ID 이모지 폴백 (`agents.list[].identity.emoji`, 없으면 &quot;👀&quot;)\n\n참고:\n\n- Discord는 유니코드 이모지 또는 커스텀 이모지 이름을 허용합니다.\n- `&quot;&quot;`를 사용하여 채널 또는 계정에 대한 반응을 비활성화하십시오.\n</code></pre></details><details class="details custom-block"><summary>Config 쓰기</summary><p>채널 시작 config 쓰기는 기본적으로 활성화되어 있습니다.</p><pre><code>이는 `/config set|unset` 흐름에 영향을 줍니다 (명령 기능이 활성화된 경우).\n\n비활성화:\n</code></pre><p>�OC_CODE_9�</p></details><details class="details custom-block"><summary>Gateway 프록시</summary><p><code>channels.discord.proxy</code>로 Discord gateway WebSocket 트래픽과 시작 시 REST 조회(application ID + 허용 목록 확인)를 HTTP(S) 프록시를 통해 라우팅합니다. �OC_CODE_10�</p><pre><code>계정별 재정의:\n</code></pre><p>�OC_CODE_11�</p></details><details class="details custom-block"><summary>PluralKit 지원</summary><p>프록시된 메시지를 시스템 멤버 ID에 매핑하려면 PluralKit 확인을 활성화하십시오: �OC_CODE_12�</p><pre><code>참고:\n\n- 허용 목록은 `pk:&amp;lt;memberId&amp;gt;`를 사용할 수 있습니다\n- 멤버 표시 이름은 `channels.discord.dangerouslyAllowNameMatching: true`일 때만 name/slug로 매칭됩니다\n- 조회는 원래 메시지 ID를 사용하며 시간 창이 제한됩니다\n- 조회에 실패하면 프록시된 메시지는 봇 메시지로 취급되어 `allowBots=true`가 아닌 한 삭제됩니다\n</code></pre></details><details class="details custom-block"><summary>Presence 구성</summary><p>상태 또는 activity 필드를 설정하거나 자동 presence를 활성화하면 presence 업데이트가 적용됩니다.</p><pre><code>상태만 예시:\n</code></pre><p>�OC_CODE_13�</p><pre><code>Activity 예시 (커스텀 상태가 기본 activity 타입):\n</code></pre><p>�OC_CODE_14�</p><pre><code>Streaming 예시:\n</code></pre><p>�OC_CODE_15�</p><pre><code>Activity 타입 맵:\n\n- 0: Playing\n- 1: Streaming (`activityUrl` 필요)\n- 2: Listening\n- 3: Watching\n- 4: Custom (activity 텍스트를 상태 state로 사용; 이모지는 선택 사항)\n- 5: Competing\n\n자동 presence 예시 (런타임 상태 신호):\n</code></pre><p>�OC_CODE_16�</p><pre><code>자동 presence는 런타임 가용성을 Discord 상태에 매핑합니다: healthy =&gt; online, degraded 또는 unknown =&gt; idle, exhausted 또는 unavailable =&gt; dnd. 선택적 텍스트 재정의:\n\n- `autoPresence.healthyText`\n- `autoPresence.degradedText`\n- `autoPresence.exhaustedText` (`{reason}` 플레이스홀더 지원)\n</code></pre></details><details class="details custom-block"><summary>Discord에서의 승인</summary><p>Discord는 DM에서 버튼 기반 승인 처리를 지원하며 선택적으로 원래 채널에 승인 프롬프트를 게시할 수 있습니다.</p><pre><code>Config 경로:\n\n- `channels.discord.execApprovals.enabled`\n- `channels.discord.execApprovals.approvers` (선택 사항; 가능한 경우 `commands.ownerAllowFrom`으로 폴백)\n- `channels.discord.execApprovals.target` (`dm` | `channel` | `both`, 기본값: `dm`)\n- `agentFilter`, `sessionFilter`, `cleanupAfterResolve`\n\nDiscord는 `enabled`가 설정되지 않았거나 `&quot;auto&quot;`이고 `execApprovals.approvers` 또는 `commands.ownerAllowFrom`에서 최소 하나의 승인자가 확인될 수 있을 때 네이티브 exec 승인을 자동 활성화합니다. Discord는 channel `allowFrom`, 레거시 `dm.allowFrom` 또는 다이렉트 메시지 `defaultTo`에서 exec 승인자를 유추하지 않습니다. Discord를 네이티브 승인 클라이언트로 명시적으로 비활성화하려면 `enabled: false`를 설정하십시오.\n\n`target`이 `channel` 또는 `both`인 경우, 승인 프롬프트는 채널에서 볼 수 있습니다. 확인된 승인자만 버튼을 사용할 수 있습니다. 다른 사용자는 ephemeral 거부를 받습니다. 승인 프롬프트는 명령 텍스트를 포함하므로, 신뢰할 수 있는 채널에서만 채널 전달을 활성화하십시오. 세션 키에서 채널 ID를 유도할 수 없으면, OpenClaw는 DM 전달로 폴백합니다.\n\nDiscord는 다른 채팅 채널에서 사용되는 공유 승인 버튼도 렌더링합니다. 네이티브 Discord 어댑터는 주로 승인자 DM 라우팅과 채널 fanout을 추가합니다.\n해당 버튼이 있을 때, 그들은 주요 승인 UX입니다. OpenClaw는 도구 결과가 채팅 승인을 사용할 수 없거나 수동 승인이 유일한 경로라고 말할 때만 수동 `/approve` 명령을 포함해야 합니다.\n\nGateway 인증 및 승인 확인은 공유 Gateway 클라이언트 계약을 따릅니다 (`plugin:` ID는 `plugin.approval.resolve`를 통해 확인되고, 다른 ID는 `exec.approval.resolve`를 통해 확인됩니다). 승인은 기본적으로 30분 후 만료됩니다.\n\n[Exec 승인](/tools/exec-approvals)을 참조하십시오.\n</code></pre></details><h2 id="도구-및-액션-게이트" tabindex="-1">도구 및 액션 게이트 <a class="header-anchor" href="#도구-및-액션-게이트" aria-label="Permalink to &quot;도구 및 액션 게이트&quot;">​</a></h2><p>Discord message 액션에는 메시징, 채널 관리, 모더레이션, presence, 메타데이터 액션이 포함됩니다.</p><p>핵심 예시:</p><ul><li>messaging: <code>sendMessage</code>, <code>readMessages</code>, <code>editMessage</code>, <code>deleteMessage</code>, <code>threadReply</code></li><li>reactions: <code>react</code>, <code>reactions</code>, <code>emojiList</code></li><li>moderation: <code>timeout</code>, <code>kick</code>, <code>ban</code></li><li>presence: <code>setPresence</code></li></ul><p><code>event-create</code> 액션은 예약된 이벤트 커버 이미지를 설정하는 선택적 <code>image</code> 매개변수(URL 또는 로컬 파일 경로)를 허용합니다.</p><p>액션 게이트는 <code>channels.discord.actions.*</code> 아래에 있습니다.</p><p>기본 게이트 동작:</p><table tabindex="0"><thead><tr><th>액션 그룹</th><th>기본값</th></tr></thead><tbody><tr><td>reactions, messages, threads, pins, polls, search, memberInfo, roleInfo, channelInfo, channels, voiceStatus, events, stickers, emojiUploads, stickerUploads, permissions</td><td>활성화</td></tr><tr><td>roles</td><td>비활성화</td></tr><tr><td>moderation</td><td>비활성화</td></tr><tr><td>presence</td><td>비활성화</td></tr></tbody></table><h2 id="components-v2-ui" tabindex="-1">Components v2 UI <a class="header-anchor" href="#components-v2-ui" aria-label="Permalink to &quot;Components v2 UI&quot;">​</a></h2><p>OpenClaw는 exec 승인 및 교차 컨텍스트 마커에 Discord components v2를 사용합니다. Discord message 액션은 커스텀 UI에 대해 <code>components</code>를 허용할 수도 있지만(고급; discord 도구를 통해 component 페이로드를 구성해야 함), 레거시 <code>embeds</code>는 여전히 사용 가능하나 권장되지 않습니다.</p><ul><li><code>channels.discord.ui.components.accentColor</code>는 Discord component 컨테이너가 사용하는 강조 색상을 설정합니다 (16진수).</li><li>계정별 설정: <code>channels.discord.accounts.&amp;lt;id&amp;gt;.ui.components.accentColor</code>.</li><li>components v2가 있을 때 <code>embeds</code>는 무시됩니다.</li></ul><p>예시: �OC_CODE_17�</p><h2 id="음성" tabindex="-1">음성 <a class="header-anchor" href="#음성" aria-label="Permalink to &quot;음성&quot;">​</a></h2><p>Discord에는 두 가지 구별되는 음성 표면이 있습니다: 실시간 <strong>voice channel</strong>(연속 대화)과 <strong>음성 메시지 첨부</strong>(waveform 미리보기 형식). Gateway는 둘 다 지원합니다.</p><h3 id="voice-channel" tabindex="-1">Voice channel <a class="header-anchor" href="#voice-channel" aria-label="Permalink to &quot;Voice channel&quot;">​</a></h3><p>요구 사항:</p><ul><li>네이티브 명령 활성화 (<code>commands.native</code> 또는 <code>channels.discord.commands.native</code>).</li><li><code>channels.discord.voice</code> 구성.</li><li>봇은 대상 voice channel에서 Connect + Speak 권한이 필요합니다.</li></ul><p><code>/vc join|leave|status</code>를 사용하여 세션을 제어합니다. 이 명령은 계정 기본 에이전트를 사용하고 다른 Discord 명령과 동일한 허용 목록 및 그룹 정책 규칙을 따릅니다.</p><p>자동 참여 예시: �OC_CODE_18�</p><p>참고:</p><ul><li><code>voice.tts</code>는 음성 재생에만 <code>messages.tts</code>를 재정의합니다.</li><li>음성 transcript 턴은 Discord <code>allowFrom</code> (또는 <code>dm.allowFrom</code>)에서 owner 상태를 유도합니다. Owner가 아닌 발화자는 owner 전용 도구(예: <code>gateway</code> 및 <code>cron</code>)에 접근할 수 없습니다.</li><li>음성은 기본적으로 활성화되어 있습니다. 비활성화하려면 <code>channels.discord.voice.enabled=false</code>를 설정하십시오.</li><li><code>voice.daveEncryption</code>과 <code>voice.decryptionFailureTolerance</code>는 <code>@discordjs/voice</code> join 옵션에 전달됩니다.</li><li><code>@discordjs/voice</code> 기본값은 설정되지 않은 경우 <code>daveEncryption=true</code>와 <code>decryptionFailureTolerance=24</code>입니다.</li><li>OpenClaw는 수신 복호화 실패도 감시하고 짧은 창 내에서 반복 실패 후 voice channel에서 나갔다가 다시 참여하여 자동 복구합니다.</li><li>수신 로그에 <code>DecryptionFailed(UnencryptedWhenPassthroughDisabled)</code>가 반복해서 표시되면, 이는 <a href="https://github.com/discordjs/discord.js/issues/11419" target="_blank" rel="noreferrer">discord.js #11419</a>에서 추적되는 업스트림 <code>@discordjs/voice</code> 수신 버그일 수 있습니다.</li></ul><h3 id="음성-메시지" tabindex="-1">음성 메시지 <a class="header-anchor" href="#음성-메시지" aria-label="Permalink to &quot;음성 메시지&quot;">​</a></h3><p>Discord 음성 메시지는 waveform 미리보기를 표시하며 OGG/Opus 오디오가 필요합니다. OpenClaw는 waveform을 자동 생성하지만, 검사 및 변환을 위해 gateway 호스트에 <code>ffmpeg</code> 및 <code>ffprobe</code>가 필요합니다.</p><ul><li><strong>로컬 파일 경로</strong>를 제공하십시오 (URL은 거부됨).</li><li>텍스트 콘텐츠는 생략하십시오 (Discord는 동일한 페이로드에서 텍스트 + 음성 메시지를 거부함).</li><li>어떤 오디오 형식이든 허용됩니다. OpenClaw는 필요에 따라 OGG/Opus로 변환합니다. �OC_CODE_19�</li></ul><h2 id="문제-해결" tabindex="-1">문제 해결 <a class="header-anchor" href="#문제-해결" aria-label="Permalink to &quot;문제 해결&quot;">​</a></h2><details class="details custom-block"><summary>허용되지 않은 intent를 사용했거나 봇이 guild 메시지를 보지 못함</summary><ul><li>Message Content Intent 활성화 <ul><li>사용자/멤버 확인에 의존하는 경우 Server Members Intent 활성화</li><li>intent 변경 후 gateway 재시작</li></ul></li></ul></details><details class="details custom-block"><summary>Guild 메시지가 예기치 않게 차단됨</summary><ul><li><p><code>groupPolicy</code> 확인</p><ul><li><code>channels.discord.guilds</code> 아래 guild 허용 목록 확인</li><li>guild <code>channels</code> 맵이 존재하면, 목록에 있는 채널만 허용됨</li><li><code>requireMention</code> 동작 및 멘션 패턴 확인</li></ul><p>유용한 확인: �OC_CODE_20�</p></li></ul></details><details class="details custom-block"><summary>requireMention false인데 여전히 차단됨</summary><p>일반적인 원인:</p><pre><code>- 일치하는 guild/channel 허용 목록 없이 `groupPolicy=&quot;allowlist&quot;`\n- `requireMention`이 잘못된 위치에 구성됨 (`channels.discord.guilds` 또는 channel 항목 아래에 있어야 함)\n- 발신자가 guild/channel `users` 허용 목록으로 차단됨\n</code></pre></details><details class="details custom-block"><summary>장기 실행 핸들러가 타임아웃되거나 응답이 중복됨</summary><p>일반적인 로그:</p><pre><code>- `Listener DiscordMessageListener timed out after 30000ms for event MESSAGE_CREATE`\n- `Slow listener detected ...`\n- `discord inbound worker timed out after ...`\n\nListener 예산 조정:\n\n- 단일 계정: `channels.discord.eventQueue.listenerTimeout`\n- 다중 계정: `channels.discord.accounts.&amp;lt;accountId&amp;gt;.eventQueue.listenerTimeout`\n\nWorker 실행 타임아웃 조정:\n\n- 단일 계정: `channels.discord.inboundWorker.runTimeoutMs`\n- 다중 계정: `channels.discord.accounts.&amp;lt;accountId&amp;gt;.inboundWorker.runTimeoutMs`\n- 기본값: `1800000` (30분); `0`으로 설정하면 비활성화\n\n권장 기준선:\n</code></pre><p>�OC_CODE_21�</p><pre><code>느린 listener 설정에는 `eventQueue.listenerTimeout`을 사용하고, 큐에 있는 에이전트 턴에 대해 별도의 안전 밸브를 원하는 경우에만 `inboundWorker.runTimeoutMs`를 사용하십시오.\n</code></pre></details><details class="details custom-block"><summary>권한 감사 불일치</summary><p><code>channels status --probe</code> 권한 확인은 숫자 채널 ID에 대해서만 작동합니다.</p><pre><code>slug 키를 사용하는 경우, 런타임 매칭은 여전히 작동할 수 있지만 probe는 권한을 완전히 확인할 수 없습니다.\n</code></pre></details><details class="details custom-block"><summary>DM 및 페어링 문제</summary><ul><li>DM 비활성화: <code>channels.discord.dm.enabled=false</code><ul><li>DM 정책 비활성화: <code>channels.discord.dmPolicy=&quot;disabled&quot;</code> (레거시: <code>channels.discord.dm.policy</code>)</li><li><code>pairing</code> 모드에서 페어링 승인 대기 중</li></ul></li></ul></details><details class="details custom-block"><summary>봇 대 봇 루프</summary><p>기본적으로 봇이 작성한 메시지는 무시됩니다.</p><pre><code>`channels.discord.allowBots=true`를 설정한 경우, 루프 동작을 피하기 위해 엄격한 멘션 및 허용 목록 규칙을 사용하십시오.\n봇을 멘션하는 봇 메시지만 허용하려면 `channels.discord.allowBots=&quot;mentions&quot;`를 선호하십시오.\n</code></pre></details><details class="details custom-block"><summary>음성 STT가 DecryptionFailed(...)로 끊김</summary><ul><li>Discord 음성 수신 복구 로직이 있도록 OpenClaw를 최신 상태로 유지하십시오 (<code>openclaw update</code>) <ul><li><code>channels.discord.voice.daveEncryption=true</code> (기본값) 확인</li><li><code>channels.discord.voice.decryptionFailureTolerance=24</code> (업스트림 기본값)부터 시작하여 필요할 때만 조정</li><li>로그에서 다음을 감시하십시오: <ul><li><code>discord voice: DAVE decrypt failures detected</code></li><li><code>discord voice: repeated decrypt failures; attempting rejoin</code></li></ul></li><li>자동 재참여 후에도 실패가 계속되면 로그를 수집하여 <a href="https://github.com/discordjs/discord.js/issues/11419" target="_blank" rel="noreferrer">discord.js #11419</a>와 비교하십시오</li></ul></li></ul></details><h2 id="구성-참조" tabindex="-1">구성 참조 <a class="header-anchor" href="#구성-참조" aria-label="Permalink to &quot;구성 참조&quot;">​</a></h2><p>기본 참조: <a href="/openclaw-docs-ko/gateway/config-channels#discord">구성 참조 - Discord</a>.</p><details class="details custom-block"><summary>고신호 Discord 필드</summary><ul><li>시작/인증: <code>enabled</code>, <code>token</code>, <code>accounts.*</code>, <code>allowBots</code></li><li>정책: <code>groupPolicy</code>, <code>dm.*</code>, <code>guilds.*</code>, <code>guilds.*.channels.*</code></li><li>명령: <code>commands.native</code>, <code>commands.useAccessGroups</code>, <code>configWrites</code>, <code>slashCommand.*</code></li><li>이벤트 큐: <code>eventQueue.listenerTimeout</code> (listener 예산), <code>eventQueue.maxQueueSize</code>, <code>eventQueue.maxConcurrency</code></li><li>인바운드 worker: <code>inboundWorker.runTimeoutMs</code></li><li>응답/히스토리: <code>replyToMode</code>, <code>historyLimit</code>, <code>dmHistoryLimit</code>, <code>dms.*.historyLimit</code></li><li>전달: <code>textChunkLimit</code>, <code>chunkMode</code>, <code>maxLinesPerMessage</code></li><li>스트리밍: <code>streaming</code> (레거시 별칭: <code>streamMode</code>), <code>streaming.preview.toolProgress</code>, <code>draftChunk</code>, <code>blockStreaming</code>, <code>blockStreamingCoalesce</code></li><li>미디어/재시도: <code>mediaMaxMb</code> (아웃바운드 Discord 업로드 제한, 기본값 <code>100MB</code>), <code>retry</code></li><li>액션: <code>actions.*</code></li><li>Presence: <code>activity</code>, <code>status</code>, <code>activityType</code>, <code>activityUrl</code></li><li>UI: <code>ui.components.accentColor</code></li><li>기능: <code>threadBindings</code>, 최상위 <code>bindings[]</code> (<code>type: &quot;acp&quot;</code>), <code>pluralkit</code>, <code>execApprovals</code>, <code>intents</code>, <code>agentComponents</code>, <code>heartbeat</code>, <code>responsePrefix</code></li></ul></details><h2 id="안전-및-운영" tabindex="-1">안전 및 운영 <a class="header-anchor" href="#안전-및-운영" aria-label="Permalink to &quot;안전 및 운영&quot;">​</a></h2><ul><li>봇 토큰을 비밀로 취급하십시오 (감독된 환경에서는 <code>DISCORD_BOT_TOKEN</code> 선호).</li><li>최소 권한 Discord 권한을 부여하십시오.</li><li>명령 배포/상태가 오래된 경우, gateway를 재시작하고 <code>openclaw channels status --probe</code>로 다시 확인하십시오.</li></ul><h2 id="관련-문서" tabindex="-1">관련 문서 <a class="header-anchor" href="#관련-문서" aria-label="Permalink to &quot;관련 문서&quot;">​</a></h2><blockquote><p><strong>페어링</strong> Discord 사용자를 gateway에 페어링합니다.</p></blockquote><blockquote><p><strong>그룹</strong> 그룹 채팅 및 허용 목록 동작.</p></blockquote><blockquote><p><strong>채널 라우팅</strong> 인바운드 메시지를 에이전트로 라우팅합니다.</p></blockquote><blockquote><p><strong>보안</strong> 위협 모델 및 강화.</p></blockquote><blockquote><p><strong>멀티 에이전트 라우팅</strong> guild와 채널을 에이전트에 매핑합니다.</p></blockquote><blockquote><p><strong>슬래시 명령</strong> 네이티브 명령 동작.</p></blockquote>',161)])])}const k=s(n,[["render",l]]);export{u as __pageData,k as default};
